code = """import json
import ast

# Load results
reviewed_businesses = locals()['var_function-call-4460847648656782561']
mongo_result = locals()['var_function-call-8584572346541733585']

if isinstance(mongo_result, str):
    with open(mongo_result, 'r') as f:
        business_list = json.load(f)
else:
    business_list = mongo_result

reviewed_ids = set()
for item in reviewed_businesses:
    ref = item['business_ref']
    if ref and '_' in ref:
        reviewed_ids.add(ref.split('_')[1])

parking_business_ids = set()
debug_info = []

for bus in business_list:
    bid_str = bus.get('business_id')
    if not bid_str:
        continue
    bid = bid_str.split('_')[1]
    
    attrs = bus.get('attributes')
    if not attrs or attrs == 'None':
        continue
        
    has_parking = False
    
    # BikeParking
    bp = attrs.get('BikeParking')
    if bp == 'True' or bp is True:
        has_parking = True
    
    # BusinessParking
    if not has_parking:
        bup = attrs.get('BusinessParking')
        if bup and bup != 'None':
            try:
                bup_val = ast.literal_eval(bup)
                if isinstance(bup_val, dict):
                    if any(bup_val.values()):
                        has_parking = True
                elif bup_val is True:
                    has_parking = True
            except:
                pass
    
    if has_parking:
        parking_business_ids.add(bid)
        if bid in reviewed_ids:
            debug_info.append(bid)

count = len(reviewed_ids.intersection(parking_business_ids))

print("__RESULT__:")
print(json.dumps({"count": count, "matched_ids": debug_info}))"""

